#include <bits/stdc++.h>
using namespace std;

const int MAX_N = 10000;
vector<bool> isPrime(MAX_N + 1, true);
vector<int> primeList;  // Stores primes up to MAX_N

// Precompute primes using Sieve of Eratosthenes
void sieve() {
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i <= MAX_N; i++) {
        if (isPrime[i]) {
            for (int j = i * i; j <= MAX_N; j += i) {
                isPrime[j] = false;
            }
        }
    }

    // Generate prime list
    for (int i = 2; i <= MAX_N; i++) {
        if (isPrime[i]) {
            primeList.push_back(i);
        }
    }
}

// Function to count primes that can be expressed as sum of consecutive primes starting from 2
int countConsecutivePrimeSums(int N) {
    int sum = 0, count = 0;

    // Iterate over prime numbers and maintain a running sum
    for (int prime : primeList) {
        sum += prime;
        if (sum > N) break;  // Stop if sum exceeds N
        if (sum != 2 && isPrime[sum]) count++;  // Exclude sum=2 from count
    }

    return count;
}

int main() {
    sieve(); // Precompute primes

    int T, N;
    cin >> T;
    while (T--) {
        cin >> N;
        cout << countConsecutivePrimeSums(N) << "\n";
    }
    return 0;
}

